/*
  RAW TOKEN LAYER
  - This file owns source values: palette constants, shadcn/radix-compatible variables,
    base radii, motion constants, and other low-level design inputs.
  - Treat these as implementation primitives, not the normal app-facing API.
  - Product code should usually consume the semantic Tailwind-facing aliases defined in
    `src/styles/index.css` (`--color-*`, `--text-*`, `--spacing-*`) instead of reaching
    straight into this file.
  - Edit this file when the underlying value or compatibility mapping changes. Edit
    `index.css` when the semantic API the rest of the app should use needs to change.

  SHADCN ↔ RADIX 12-STEP NOTES
  - Keep the upstream shadcn variable names so imports remain drop-in compatible
  - token is the surface/fill color (buttons, cards, badges)
  - token-foreground is the content on that surface
  - Neutrals map directly to Gray (background/card/popover = step 1, etc.).
  - Semantic tokens (primary/accent/destructive/success) pick saturated step 9 surfaces with step 11-ish foregrounds.
  - Light mode values stay opaque (no opacity hacks) so the contrast lives inside each pair.
  - Original shadcn vars: https://ui.shadcn.com/docs/theming#list-of-variables

  NB! For custom color scales we defer to the radix system. It is far more sensible! See: https://www.radix-ui.com/colors/docs/palette-composition/understanding-the-scale
*/

:root {
  --spacing: 4px;
  --radius: 9px;
  --icon-stroke-width: 1.5;

  /* Motion */
  --motion-lg: 200ms;
  --ease-standard: cubic-bezier(0.2, 0, 0, 1);

  /* Gray scale (using Shadcn naming + radix step 11) */
  --background: oklch(1 0 0); /* step 1: white */
  --foreground: oklch(0.145 0 0); /* step 12: #0a0a0a */
  --foreground-11: oklch(0.5032 0 0); /* Gray 11 #646464 */
  --muted-foreground: oklch(0.61 0 0); /* Gray 10 #838383; was 0.556 */
  --muted: oklch(0.97 0 0); /* step 2-3 #f5f5f5 */
  --border: oklch(0.922 0 0); /* step 4-5 */
  --input: oklch(0.815 0 0); /* step 7-8: was oklch(0.922 0 0) */
  --ring: oklch(0.708 0 0); /* step 8-9 */

  /* Destructive red scale */
  --destructive: oklch(0.577 0.245 27.325);
  --destructive-foreground: color-mix(in oklch, var(--destructive) 90%, black);
  --destructive-reversed: color-mix(in oklch, var(--destructive) 10%, white);

  /* Success green scale */
  --success: oklch(0.7699 0.212 148.6); /* #20D760 */
  --success-foreground: color-mix(in oklch, var(--success) 90%, black);
  --success-reversed: color-mix(in oklch, var(--success) 10%, white);

  /* Warning amber scale */
  --warning: oklch(66.6% 0.179 58.318); /* tailwind amber-600 */
  --warning-foreground: color-mix(in oklch, var(--warning) 90%, black);
  --warning-reversed: color-mix(in oklch, var(--warning) 10%, white);

  /* Accents */
  --accent-primary: oklch(0.5812 0.1716 253.66); /* #187adc */
  --accent-secondary: oklch(0.6941 0.0814 60.8); /* #C29168 */
  --accent-surface: oklch(0.9668 0.0054 95.1); /* #F5F4F0 */

  /* Accent blue scale (anchor: #4141fc):  */
  /* Made with: https://www.radix-ui.com/colors/custom */
  --accent-example: oklch(0.4248 0.1505 290.12); /* #4141fc */
  --accent-1: oklch(99.4% 0.0021 272);
  --accent-2: oklch(98.3% 0.011 272);
  --accent-3: oklch(96.1% 0.0234 272);
  --accent-4: oklch(93.5% 0.0461 272);
  --accent-5: oklch(90.3% 0.0698 272);
  --accent-6: oklch(86.3% 0.0973 272);
  --accent-7: oklch(80.7% 0.1185 272);
  --accent-8: oklch(73% 0.1547 272);
  --accent-9: var(--accent-example);
  --accent-10: oklch(46.8% 0.2357 272);
  --accent-11: oklch(51% 0.2357 272);
  --accent-12: oklch(31.3% 0.1173 272);

  /* UNUSED */
  /* Keep to ensure Shadcn imports remain smooth */
  --card: oklch(1 0 0);
  --card-foreground: oklch(0.145 0 0);
  --popover: oklch(1 0 0);
  --popover-foreground: oklch(0.145 0 0);
  --primary: oklch(0.205 0 0);
  --primary-foreground: oklch(0.985 0 0);
  --secondary: oklch(0.97 0 0); /* step 2-3 */
  --secondary-foreground: oklch(0.205 0 0);
  --chart-1: oklch(0.646 0.222 41.116);
  --chart-2: oklch(0.6 0.118 184.704);
  --chart-3: oklch(0.398 0.07 227.392);
  --chart-4: oklch(0.828 0.189 84.429);
  --chart-5: oklch(0.769 0.188 70.08);
  --sidebar: oklch(0.985 0 0);
  --sidebar-foreground: oklch(0.145 0 0);
  --sidebar-primary: oklch(0.205 0 0);
  --sidebar-primary-foreground: oklch(0.985 0 0);
  --sidebar-accent: oklch(0.97 0 0);
  --sidebar-accent-foreground: oklch(0.205 0 0);
  --sidebar-border: oklch(0.922 0 0);
  --sidebar-ring: oklch(0.708 0 0);
}

/* TODO: add dark versions of the above custom colors */
.dark {
  --background: oklch(0.145 0 0);
  --foreground: oklch(0.985 0 0);
  --card: oklch(0.205 0 0);
  --card-foreground: oklch(0.985 0 0);
  --popover: oklch(0.205 0 0);
  --popover-foreground: oklch(0.985 0 0);
  --primary: oklch(0.87 0 0);
  --primary-foreground: oklch(0.205 0 0);
  --secondary: oklch(0.269 0 0);
  --secondary-foreground: oklch(0.985 0 0);
  --muted: oklch(0.269 0 0);
  --muted-foreground: oklch(0.708 0 0);
  --accent: oklch(0.371 0 0);
  --accent-foreground: oklch(0.985 0 0);
  --destructive: oklch(0.704 0.191 22.216);
  --border: oklch(1 0 0 / 10%);
  --input: oklch(1 0 0 / 15%);
  --ring: oklch(0.556 0 0);
  --chart-1: oklch(0.809 0.105 251.813);
  --chart-2: oklch(0.623 0.214 259.815);
  --chart-3: oklch(0.546 0.245 262.881);
  --chart-4: oklch(0.488 0.243 264.376);
  --chart-5: oklch(0.424 0.199 265.638);
  --sidebar: oklch(0.205 0 0);
  --sidebar-foreground: oklch(0.985 0 0);
  --sidebar-primary: oklch(0.488 0.243 264.376);
  --sidebar-primary-foreground: oklch(0.985 0 0);
  --sidebar-accent: oklch(0.269 0 0);
  --sidebar-accent-foreground: oklch(0.985 0 0);
  --sidebar-border: oklch(1 0 0 / 10%);
  --sidebar-ring: oklch(0.556 0 0);
}

/*
  https://tailwindcss.com/docs/adding-custom-styles#adding-custom-utilities

  `@utility` defines reusable Tailwind utilities.
  Use it for single-purpose helpers you want available to both markup and `@apply`.
*/

@utility link {
  @apply relative;
  @apply underline underline-offset-[0.25em];
  @apply decoration-solid decoration-[0.025em];
  @apply hover:text-current hover:decoration-current hover:decoration-[0.05em];
  @apply transition-colors duration-200 ease-linear;
}

@utility container {
  @apply px-inset mx-auto w-full;
  @apply max-w-container;
}

/* 
  Safe-area utilities for iOS insets. 
  No-op outside environments that expose these env vars. 
 */
@utility safe-area-top {
  padding-top: env(safe-area-inset-top);
}
@utility safe-area-bottom {
  padding-bottom: env(safe-area-inset-bottom);
}
@utility safe-area-left {
  padding-left: env(safe-area-inset-left);
}
@utility safe-area-right {
  padding-right: env(safe-area-inset-right);
}
@utility safe-area-inset {
  padding: env(safe-area-inset-top) env(safe-area-inset-right)
    env(safe-area-inset-bottom) env(safe-area-inset-left);
}

/*
  Full viewport height with `dvh` for mobile browser chrome.
  Use `svh` instead if you want scroll-stable height.
  https://developer.mozilla.org/en-US/docs/Web/CSS/length#relative_length_units_based_on_viewport
*/
@utility h-viewport {
  /* legacy vh fallback */
  min-height: 100vh;
  /* Dynamic viewport height. If you want “never grow on scroll even on modern browsers” swap to svh. */
  min-height: 100dvh;
}

/* 
  Tailwind's utilities layer is the last class layer in the cascade. Classes here are easy to override only with other utilities. They are not `@apply`-able unless also defined with `@utility`. 
 */
@layer utilities {
  /* Absolute device viewport height with safe areas. Applied to body element; owns viewport min-height (+ iOS override) */
  .viewport-wrapper {
    @apply h-viewport safe-area-top safe-area-bottom;
  }
  /* Target a child content div to inherit the viewport min-height. This helps us track where the viewport height is being used, making it easy to test and update. */
  .viewport-wrapper-child {
    @apply min-h-[inherit];
  }

  /* reusable gradient example */
  .viewport-gradient {
    @apply from-accent/20 via-accent/10 to-background bg-linear-to-t via-20% to-50%;
  }

  /* consistent screen layout example */
  .auth-screen-content {
    max-width: 480px;
    @apply container px-inset;
    @apply space-y-6;
    @apply mb-[10vh];
  }

  /* These are plain classes. Use them directly in markup. Do NOT @apply them unless you also promote them to @utility. */
  .link-block a:not(.Button) {
    @apply link;
  }

  /* must add a height when used within a flex parent */
  .hr-vertical {
    @apply w-px border-l;
  }

  /* https://sebhastian.com/hide-scrollbar-css/ */
  /* If you ever need to `@apply hide-scrollbar`, change this to `@utility hide-scrollbar` */
  /* Firefox */
  .hide-scrollbar {
    scrollbar-width: none;
  }
  .hide-scrollbar::-webkit-scrollbar {
    display: none;
  }
}

@import "tailwindcss";
@import "tw-animate-css";
@import "shadcn/tailwind.css";

/*
 * Keep token imports ordered:
 * `tokens-primitive.css` defines source values, `tokens-semantic.css` derives
 * fluid values and maps them to ds-kit theme variables, `tailwind-aliases.css`
 * remaps Tailwind's default names onto those semantic tokens, and later files
 * consume that public token surface.
 */
@import "./tokens-primitive.css";
@import "./tokens-semantic.css";
@import "./tailwind-aliases.css";
@import "./utils.css";
@import "./icons.css";
@import "./animations.css";

@custom-variant dark (&:is(.dark *));

/* Tailwind base: global defaults below utilities */
@layer base {
  * {
    scrollbar-width: thin;
    @apply border-border outline-ring/50;
  }
  ::selection {
    @apply bg-foreground text-background;
  }
  ::after,
  ::before,
  ::backdrop,
  ::file-selector-button {
    @apply border-border;
  }
  html {
    @apply bg-background text-foreground;
    @apply min-h-dvh;
  }
  body {
    font-synthesis: none;
    text-rendering: optimizeLegibility;
    /* transition everywhere: do NOT use tailwind's @apply here as the variables are inherited on every child transition */
    transition:
      color var(--motion-lg) var(--ease-standard),
      opacity var(--motion-lg) var(--ease-standard);
    @apply bg-background text-foreground;
    @apply font-sans text-body font-normal antialiased;
    @apply h-full min-h-dvh;
  }
  input::placeholder,
  textarea::placeholder {
    @apply text-muted-foreground;
  }
  button:not(:disabled),
  [role="button"]:not(:disabled) {
    @apply cursor-pointer;
  }
}

/*
 * Private fluid math lives in `:root`; public ds-kit tokens live in `@theme`.
 * Keep `--fluid-*` out of the theme namespace so `@theme` stays the semantic
 * contract, including the guarded `--text-*: initial;` reset below.
 */
:root {
  /*
   * Fluid interpolation step: 0px at <=500px, 1px at >=1200px.
   * All tokens use calc(min + (range * var(--fluid-step))).
   *
   * Chrome 131 does not support the newer typed-arithmetic pattern that
   * divides one length by another length to produce a unitless number:
   *   (100vw - 500px) / 700px
   *
   * Keep the same DX, but store the step as a clamped 0px..1px length:
   *   --fluid-step: max(0px, min(1px, calc((100vw - 500px) / 700)));
   *
   * Tokens then multiply by a unitless range:
   *   calc(14px + (2 * var(--fluid-step)))
   */
  --fluid-step: max(0px, min(1px, calc((100vw - 500px) / 700)));

  /* Text */
  --fluid-text-pill: calc(9px + (1.5 * var(--fluid-step)));
  --fluid-text-fine: calc(10px + (2.5 * var(--fluid-step)));
  --fluid-text-compact: calc(11px + (2 * var(--fluid-step)));
  --fluid-text-small: calc(12px + (3 * var(--fluid-step)));
  --fluid-text-body: calc(14px + (2 * var(--fluid-step)));
  --fluid-text-large: calc(15px + (2 * var(--fluid-step)));
  --fluid-text-xlarge: calc(17px + (3 * var(--fluid-step)));
  --fluid-text-heading: calc(18px + (4 * var(--fluid-step)));
  --fluid-text-subtitle: calc(20px + (5 * var(--fluid-step)));
  --fluid-text-title: calc(25px + (7 * var(--fluid-step)));
  --fluid-text-display: calc(32px + (8 * var(--fluid-step)));
  --fluid-text-hero: calc(40px + (10 * var(--fluid-step)));

  /* Spacing: named */
  --fluid-spacing-nav: calc(72px + (20 * var(--fluid-step)));
  --fluid-spacing-header: calc(56px + (8 * var(--fluid-step)));
  --fluid-spacing-banner: calc(24px + (8 * var(--fluid-step)));
  --fluid-spacing-button-xs: calc(24px + (4 * var(--fluid-step)));
  --fluid-spacing-tab: calc(44px + (10 * var(--fluid-step)));

  /* Spacing: scale */
  --fluid-spacing-w4: calc(10.5px + (5.5 * var(--fluid-step)));
  --fluid-spacing-w5: calc(12px + (8 * var(--fluid-step)));
  --fluid-spacing-w6: calc(16px + (8 * var(--fluid-step)));
  --fluid-spacing-w7: calc(18px + (9 * var(--fluid-step)));
  --fluid-spacing-w8: calc(21px + (11 * var(--fluid-step)));
  --fluid-spacing-w10: calc(28px + (12 * var(--fluid-step)));
  --fluid-spacing-w12: calc(32px + (16 * var(--fluid-step)));
  --fluid-spacing-w16: calc(43px + (21 * var(--fluid-step)));
  --fluid-spacing-w18: calc(48px + (23 * var(--fluid-step)));
  --fluid-spacing-w20: calc(54px + (26 * var(--fluid-step)));
  --fluid-spacing-w24: calc(64px + (32 * var(--fluid-step)));
  --fluid-spacing-w28: calc(75px + (37 * var(--fluid-step)));
  --fluid-spacing-w32: calc(85px + (43 * var(--fluid-step)));
  --fluid-spacing-w36: calc(96px + (48 * var(--fluid-step)));
  --fluid-spacing-w42: calc(112px + (56 * var(--fluid-step)));
  --fluid-spacing-w48: calc(128px + (64 * var(--fluid-step)));
  --fluid-spacing-w64: calc(171px + (85 * var(--fluid-step)));
  --fluid-spacing-w72: calc(192px + (96 * var(--fluid-step)));
  --fluid-spacing-w96: calc(256px + (128 * var(--fluid-step)));
}

/*
  NB! Use "inline" when defining theme variables that reference other variables:
  https://tailwindcss.com/docs/theme#using-your-theme-variables
 */
@theme inline {
  /*
   * Reset the Tailwind text namespace before declaring semantic text tokens.
   * Keeping this in its own block makes the reset order explicit and protects it
   * from formatters or future edits that might move it below concrete `--text-*`
   * declarations, which would break utility registration.
   * See: history/260409-ultracite-cursor-css-formatting.md
   */
  --text-*: initial;
}

@theme inline {
  /* text size */
  --text-pill: var(--fluid-text-pill);
  --text-fine: var(--fluid-text-fine);
  --text-compact: var(--fluid-text-compact);
  --text-small: var(--fluid-text-small);
  --text-body: var(--fluid-text-body);
  --text-button: 16px; /* keep controls at 16px to avoid iOS form zoom */
  --text-large: var(--fluid-text-large);
  --text-xlarge: var(--fluid-text-xlarge);
  --text-heading: var(--fluid-text-heading);
  --text-subtitle: var(--fluid-text-subtitle);
  --text-title: var(--fluid-text-title);
  --text-display: var(--fluid-text-display);
  --text-hero: var(--fluid-text-hero);

  /* text line-height */
  --default-line-height: calc(24 / 17);
  --text-pill--line-height: 1;
  --text-fine--line-height: var(--default-line-height);
  --text-compact--line-height: var(--default-line-height);
  --text-small--line-height: var(--default-line-height);
  --text-body--line-height: var(--default-line-height);
  --text-button--line-height: var(--default-line-height);
  --text-large--line-height: var(--default-line-height);
  --text-xlarge--line-height: 1.3;
  --text-heading--line-height: 1.25;
  --text-subtitle--line-height: 1.25;
  --text-title--line-height: 1.1;
  --text-display--line-height: 1;
  --text-hero--line-height: 1;

  /* text letter-spacing (0 is default) */
  --text-pill--letter-spacing: 0.025em;
  --text-fine--letter-spacing: 0.0175em;
  --text-compact--letter-spacing: 0.005em;
  --text-body--letter-spacing: 0;
  --text-button--letter-spacing: 0;
  --text-xlarge--letter-spacing: -0.01em;
  --text-heading--letter-spacing: -0.01em;
  --text-subtitle--letter-spacing: -0.01em;
  --text-title--letter-spacing: -0.01em;
  --text-display--letter-spacing: -0.015em;
  --text-hero--letter-spacing: -0.02em;

  /* spacing */
  --spacing-em: 1em;
  --spacing-lh: 1lh;
  --spacing-inset: 24px; /* static for use with calc() */
  --spacing-button: 44px;
  --spacing-prose: 65ch;
  --spacing-panel: 520px;
  --spacing-container: 960px;
  --spacing-frame: 1000px;
  /* Bridge prose token into Tailwind's max-width token namespace for `max-w-prose`. */
  --max-width-prose: var(--spacing-prose);

  --spacing-nav: var(--fluid-spacing-nav);
  --spacing-header: var(--fluid-spacing-header);
  --spacing-tab: var(--fluid-spacing-tab);
  --spacing-banner: var(--fluid-spacing-banner);
  --spacing-bar: var(--fluid-spacing-w8);
  --spacing-button-xs: var(--fluid-spacing-button-xs);

  --spacing-gap: var(--fluid-spacing-w4);
  --spacing-small: var(--fluid-spacing-w6);
  --spacing-minor: var(--fluid-spacing-w10);
  --spacing-mid: var(--fluid-spacing-w18);
  --spacing-major: var(--fluid-spacing-w24);
  --spacing-super: var(--fluid-spacing-w48);

  --spacing-w4: var(--fluid-spacing-w4);
  --spacing-w5: var(--fluid-spacing-w5);
  --spacing-w6: var(--fluid-spacing-w6);
  --spacing-w8: var(--fluid-spacing-w8);
  --spacing-w10: var(--fluid-spacing-w10);
  --spacing-w12: var(--fluid-spacing-w12);
  --spacing-w16: var(--fluid-spacing-w16);
  --spacing-w18: var(--fluid-spacing-w18);
  --spacing-w20: var(--fluid-spacing-w20);
  --spacing-w24: var(--fluid-spacing-w24);
  --spacing-w28: var(--fluid-spacing-w28);
  --spacing-w32: var(--fluid-spacing-w32);
  --spacing-w36: var(--fluid-spacing-w36);
  --spacing-w42: var(--fluid-spacing-w42);
  --spacing-w48: var(--fluid-spacing-w48);
  --spacing-w64: var(--fluid-spacing-w64);
  --spacing-w72: var(--fluid-spacing-w72);
  --spacing-w96: var(--fluid-spacing-w96);

  /* radius */
  --radius-soft: calc(var(--radius) / 3);
  --radius-button: calc(var(--radius) * 5 / 9);
  --radius-card: var(--radius);
  --radius-squish: calc(var(--radius) * 1.333);
  --radius-dialog: calc(var(--radius) * 2.667);

  /* colors */
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-foreground-dim: var(--foreground-11);
  --color-foreground-muted: var(--muted-foreground);

  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);

  --color-destructive: var(--destructive);
  --color-destructive-foreground: var(--destructive-foreground);
  --color-destructive-reversed: var(--destructive-reversed);
  --color-success: var(--success);
  --color-success-foreground: var(--success-foreground);
  --color-success-reversed: var(--success-reversed);
  --color-warning: var(--warning);
  --color-warning-foreground: var(--warning-foreground);
  --color-warning-reversed: var(--warning-reversed);

  /* accent examples using color-mix */
  --color-accent: var(--odl-accent);
  --color-accent-foreground: color-mix(in oklab, var(--odl-accent) 85%, black);
  --color-highlight: var(--odl-gold);
  --color-highlight-foreground: color-mix(in oklab, var(--odl-gold) 85%, black);
  --color-panel: var(--accent-surface);
  --color-panel-subtle: color-mix(in oklab, var(--accent-surface) 30%, white);

  /* accent example using radix color tokens */
  --color-accent-canvas: var(--accent-1);
  --color-accent-subtle: var(--accent-2);
  --color-accent-surface: var(--accent-3);
  --color-accent-surface-hover: var(--accent-4);
  --color-accent-surface-active: var(--accent-5);
  --color-accent-border: var(--accent-6);
  --color-accent: var(--accent-9);
  --color-accent-foreground-dim: var(--accent-11);
  --color-accent-foreground: var(--accent-12);

  /* unused tailwind default colors; keep for smooth shadcn imports */
  --color-sidebar-ring: var(--sidebar-ring);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar: var(--sidebar);
  --color-chart-5: var(--chart-5);
  --color-chart-4: var(--chart-4);
  --color-chart-3: var(--chart-3);
  --color-chart-2: var(--chart-2);
  --color-chart-1: var(--chart-1);
  --color-popover-foreground: var(--popover-foreground);
  --color-popover: var(--popover);
  --color-card-foreground: var(--card-foreground);
  --color-card: var(--card);
}

/* Runtime override for the public token; keep declaration in `@theme`. */
@media (max-width: 640px) {
  :root {
    --spacing-inset: 15px;
  }
}

/**
 * Tailwind-facing default theme variable names → ds-kit semantic tokens.
 * @see https://tailwindcss.com/docs/theme#default-theme-variable-reference
 *
 * Keep this file focused on Tailwind's default variable names. Semantic tokens
