      data-slot="button"
      type={
        type ??
        ("button" satisfies React.ButtonHTMLAttributes<HTMLButtonElement>["type"])
      }
      {...(selected && {
        "data-state": "open",
        "aria-pressed": true,
        "aria-selected": true,
      })}
      {...props}
    />
  );
}

function ButtonLink({
